import{_ as a,c as t,o as s,ae as n}from"./chunks/framework.Cd-3tpCq.js";const g=JSON.parse('{"title":"Étape 1.1 — Différence entre une \\"Canvas Page\\" et un nœud classique","description":"","frontmatter":{},"headers":[],"relativePath":"drupal-canvas/canvas-vs-node.md","filePath":"drupal-canvas/canvas-vs-node.md"}'),r={name:"drupal-canvas/canvas-vs-node.md"};function i(o,e,l,u,d,p){return s(),t("div",null,e[0]||(e[0]=[n(`<h1 id="etape-1-1-—-difference-entre-une-canvas-page-et-un-nœud-classique" tabindex="-1">Étape 1.1 — Différence entre une &quot;Canvas Page&quot; et un nœud classique <a class="header-anchor" href="#etape-1-1-—-difference-entre-une-canvas-page-et-un-nœud-classique" aria-label="Permalink to &quot;Étape 1.1 — Différence entre une &quot;Canvas Page&quot; et un nœud classique&quot;">​</a></h1><h2 id="le-nœud-drupal-classique-un-rappel" tabindex="-1">Le nœud Drupal classique : un rappel <a class="header-anchor" href="#le-nœud-drupal-classique-un-rappel" aria-label="Permalink to &quot;Le nœud Drupal classique : un rappel&quot;">​</a></h2><p>Avant <strong>Drupal Canvas</strong>, la manière traditionnelle de créer du contenu dans <strong>Drupal</strong> reposait sur les <strong>nœuds</strong> (nodes).</p><p>Un <strong>nœud</strong>, c&#39;est :</p><ul><li>Un formulaire de saisie avec des champs définis à l&#39;avance (titre, corps, image…).</li><li>Un rendu visuel disponible uniquement après sauvegarde (on ne voit pas le résultat en temps réel).</li><li>Une gestion via <code>Administration → Contenu</code>.</li></ul><div class="warning custom-block"><p class="custom-block-title">⚠️ Le problème</p><p>L&#39;éditeur travaille &quot;à l&#39;aveugle&quot;. Il remplit des champs sans voir à quoi ressemblera la page finale. C&#39;est puissant mais peu intuitif pour un non-développeur.</p></div><h2 id="la-canvas-page-une-approche-radicalement-differente" tabindex="-1">La Canvas Page : une approche radicalement différente <a class="header-anchor" href="#la-canvas-page-une-approche-radicalement-differente" aria-label="Permalink to &quot;La Canvas Page : une approche radicalement différente&quot;">​</a></h2><p>Une <strong>Canvas Page</strong> est un nouveau type d&#39;entité introduit par <strong>Drupal Canvas</strong>. Ce n&#39;est pas un <strong>nœud</strong>, c&#39;est une entité totalement distincte dans <strong>Drupal</strong>.</p><p>Elle apporte :</p><ul><li>Une interface <strong>WYSIWYG</strong> (<em>What You See Is What You Get</em>) : vous construisez la page directement dans le navigateur et voyez le résultat en temps réel.</li><li>Une construction par assemblage de composants visuels plutôt que par remplissage de champs.</li><li>Un rendu immédiat sans avoir à sauvegarder pour voir le résultat.</li></ul><div class="tip custom-block"><p class="custom-block-title">Analogie</p><p>Si un <strong>nœud</strong> classique, c&#39;est comme remplir un formulaire <strong>Word</strong>, une <strong>Canvas Page</strong>, c&#39;est comme travailler directement dans <strong>Figma</strong> ou <strong>Canva</strong>. Vous voyez, vous déplacez, vous ajustez.</p></div><h2 id="installer-drupal-canvas" tabindex="-1">Installer Drupal Canvas <a class="header-anchor" href="#installer-drupal-canvas" aria-label="Permalink to &quot;Installer Drupal Canvas&quot;">​</a></h2><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ddev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> composer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> require</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> drupal/canvas</span></span></code></pre></div><h2 id="ou-trouver-les-canvas-pages-dans-l-administration" tabindex="-1">Où trouver les Canvas Pages dans l&#39;administration ? <a class="header-anchor" href="#ou-trouver-les-canvas-pages-dans-l-administration" aria-label="Permalink to &quot;Où trouver les Canvas Pages dans l&#39;administration ?&quot;">​</a></h2><p>Les Canvas Pages ont leur propre espace dans l&#39;administration, séparé des contenus classiques. Chemin d&#39;accès : <code>Administration → Contenu → Pages</code></p><p>ou via le menu de navigation rapide en haut de l&#39;interface : <code>Drupal Canvas (lien dédié dans la barre d&#39;administration)</code></p><div class="tip custom-block"><p class="custom-block-title">À noter</p><p>L&#39;onglet &quot;Contenu&quot; liste vos <strong>nœuds</strong> classiques, tandis que l&#39;onglet &quot;Pages&quot; liste vos <strong>Canvas Pages</strong>.</p><p>Ce sont deux espaces bien distincts.</p></div><h2 id="la-hierarchie-d-une-canvas-page" tabindex="-1">La hiérarchie d&#39;une Canvas Page <a class="header-anchor" href="#la-hierarchie-d-une-canvas-page" aria-label="Permalink to &quot;La hiérarchie d&#39;une Canvas Page&quot;">​</a></h2><p>Une Canvas Page est structurée selon une hiérarchie en 3 niveaux :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PAGE</span></span>
<span class="line"><span>   └──  SECTION  (ex: &quot;Bloc Hero&quot;, &quot;Section services&quot;, &quot;Footer&quot;)</span></span>
<span class="line"><span>      └──  COMPOSANT  (ex: titre, image, bouton, carte…)</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Niveau</th><th>Rôle</th><th>Analogie</th></tr></thead><tbody><tr><td><strong>Page</strong></td><td>La page web complète</td><td>Une feuille entière</td></tr><tr><td><strong>Section</strong></td><td>Un grand bloc horizontal</td><td>Une rangée sur la feuille</td></tr><tr><td><strong>Composant</strong></td><td>Un élément de contenu</td><td>Un mot, une image, un bouton</td></tr></tbody></table><h2 id="canvas-page-vs-nœud-tableau-comparatif" tabindex="-1">Canvas Page vs Nœud : tableau comparatif <a class="header-anchor" href="#canvas-page-vs-nœud-tableau-comparatif" aria-label="Permalink to &quot;Canvas Page vs Nœud : tableau comparatif&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Caractéristique</th><th>Nœud classique</th><th>Canvas Page</th></tr></thead><tbody><tr><td><strong>Interface</strong></td><td>Formulaire de champs</td><td>Éditeur visuel WYSIWYG</td></tr><tr><td><strong>Prévisualisation</strong></td><td>Après sauvegarde</td><td>En temps réel</td></tr><tr><td><strong>Structure</strong></td><td>Fixée par le type de contenu</td><td>Libre, par assemblage</td></tr><tr><td><strong>Public cible</strong></td><td>Développeurs / éditeurs techniques</td><td>Tous profils, y compris non-techniques</td></tr><tr><td><strong>Localisation admin</strong></td><td>Contenu → Contenu</td><td>Contenu → Pages</td></tr><tr><td><strong>Type d&#39;entité</strong></td><td>Node</td><td>Canvas Page (entité distincte)</td></tr><tr><td><strong>Idéal pour</strong></td><td>Articles, fiches produits, données structurées</td><td>Pages marketing, landing pages, homepage</td></tr></tbody></table><h2 id="quand-utiliser-canvas-plutot-qu-un-nœud" tabindex="-1">Quand utiliser Canvas plutôt qu&#39;un nœud ? <a class="header-anchor" href="#quand-utiliser-canvas-plutot-qu-un-nœud" aria-label="Permalink to &quot;Quand utiliser Canvas plutôt qu&#39;un nœud ?&quot;">​</a></h2><p>Utilisez une Canvas Page pour :</p><ul><li>✅ La page d&#39;accueil.</li><li>✅ Les landing pages marketing.</li><li>✅ Les pages &quot;À propos&quot;, &quot;Contact&quot;, &quot;Services&quot;.</li><li>✅ Toute page avec une mise en page unique et créative.</li></ul><p>Utilisez un nœud classique pour :</p><ul><li>✅ Les articles de blog (contenu répétitif et structuré).</li><li>✅ Les fiches produits (données structurées avec des champs précis).</li><li>✅ Les événements, offres d&#39;emploi, etc.</li><li>✅ Tout contenu géré en grande quantité.</li></ul><div class="info custom-block"><p class="custom-block-title">Bonne pratique</p><p><strong>Canvas</strong> et les <strong>nœuds</strong> sont complémentaires. Une <strong>Canvas Page</strong> peut d&#39;ailleurs afficher une liste d&#39;articles (nœuds) via un composant dédié. Les deux coexistent sur le même site.</p></div>`,29)]))}const v=a(r,[["render",i]]);export{g as __pageData,v as default};
